arguments.command:
$envLines = Get-Content .env.local
foreach ($line in $envLines) { if ($line -match '^(.*?)=(.*)$') { [System.Environment]::SetEnvironmentVariable($matches[1], $matches[2]) } }
$headers = @{ 'apikey' = $env:SUPABASE_SERVICE_ROLE_KEY; 'Authorization' = "Bearer $env:SUPABASE_SERVICE_ROLE_KEY"; 'Content-Type' = 'application/json' }
$email = 'jjtorresrojas0001@hotmail.com'
try {
  $list = Invoke-RestMethod -Method Get -Uri "$env:NEXT_PUBLIC_SUPABASE_URL/auth/v1/admin/users?page=1&per_page=1000" -Headers $headers
  $user = $list.users | Where-Object { $_.email -eq $email } | Select-Object -First 1
  if (-not $user) { throw "User not found: $email" }

  $profileBody = @{ id = $user.id; plan = 'beta'; plan_expires_at = $null } | ConvertTo-Json
  $profileHeaders = @{ 'apikey' = $env:SUPABASE_SERVICE_ROLE_KEY; 'Authorization' = "Bearer $env:SUPABASE_SERVICE_ROLE_KEY"; 'Content-Type' = 'application/json'; 'Prefer' = 'resolution=merge-duplicates,return=representation' }
  Invoke-RestMethod -Method Post -Uri "$env:NEXT_PUBLIC_SUPABASE_URL/rest/v1/user_profiles?on_conflict=id" -Headers $profileHeaders -Body $profileBody | Out-Null

  Write-Output ("EMAIL=" + $email)
  Write-Output ("USER_ID=" + $user.id)
  Write-Output ("PLAN=beta")
} catch {
  Write-Output $_.Exception.Message
  if ($_.ErrorDetails.Message) { Write-Output $_.ErrorDetails.Message }
  exit 1
}

